if (!defined('CLI_SCRIPT')) { define('CLI_SCRIPT', true); }
require('/www/moodle/config.php');
require_once($CFG->libdir . '/moodlelib.php');
require_once($CFG->dirroot . '/course/lib.php');
require_once($CFG->dirroot . '/local/sandbox/locallib.php');
try {
    global $DB, $USER, $CFG;
    $USER = get_admin();

    // Restore synchronously so the scheduled task performs the restore inline.
    set_config('enableasyncbackup', 0);

    // Configure the plugin so its scheduled task can reset the sandbox course.
    set_config('adjustcoursestartdate', 1, 'local_sandbox');
    set_config('keepcourseid', 1, 'local_sandbox');
    set_config('keepcoursename', 1, 'local_sandbox');
    set_config('restore_general_users', 0, 'local_sandbox');
    set_config('restore_general_enrolments', 2, 'local_sandbox');
    set_config('restore_general_role_assignments', 0, 'local_sandbox');
    set_config('restore_general_activities', 1, 'local_sandbox');
    set_config('restore_general_blocks', 1, 'local_sandbox');
    set_config('restore_general_filters', 0, 'local_sandbox');
    set_config('restore_general_comments', 0, 'local_sandbox');
    set_config('restore_general_badges', 0, 'local_sandbox');
    set_config('restore_general_calendarevents', 0, 'local_sandbox');
    set_config('restore_general_userscompletion', 0, 'local_sandbox');
    set_config('restore_general_logs', 0, 'local_sandbox');
    set_config('restore_general_histories', 0, 'local_sandbox');
    set_config('restore_general_groups', 0, 'local_sandbox');
    set_config('restore_general_competencies', 0, 'local_sandbox');
    set_config('notifylevel', SANDBOX_LEVEL_ERROR, 'local_sandbox');
    set_config('notifyonerrors', '', 'local_sandbox');

    // Create the demo category and sandbox course from PHP so the setup is
    // self-contained and does not depend on declarative blueprint steps.
    $category = $DB->get_record('course_categories', ['name' => 'Sandbox Courses']);
    if (!$category) {
        $category = \core_course_category::create((object) ['name' => 'Sandbox Courses']);
    }
    $categoryid = is_object($category) ? $category->id : $category;

    // The sandbox course must exist and its shortname has to match the backup filename.
    $course = $DB->get_record('course', ['shortname' => 'sandbox-test']);
    if (!$course) {
        $course = create_course((object) [
            'fullname' => 'Sandbox Test Course',
            'shortname' => 'sandbox-test',
            'category' => $categoryid,
            'summary' => 'Demo sandbox course that local_sandbox automatically resets from a bundled course backup.',
            'summaryformat' => FORMAT_HTML,
        ]);
    }

    // Upload the sample course backup that ships with the plugin (tests/fixtures)
    // into the plugin's filearea, named <shortname>.mbz, so the task has something
    // to restore.
    $syscontext = \context_system::instance();
    $fs = get_file_storage();
    if (!$fs->file_exists($syscontext->id, 'local_sandbox', 'coursebackups', 0, '/', 'sandbox-test.mbz')) {
        $source = $CFG->dirroot . '/local/sandbox/tests/fixtures/sandbox-test.mbz';
        if (!file_exists($source)) {
            throw new \RuntimeException('The bundled sandbox-test.mbz backup fixture was not found.');
        }
        $fs->create_file_from_pathname([
            'contextid' => $syscontext->id,
            'component' => 'local_sandbox',
            'filearea'  => 'coursebackups',
            'itemid'    => 0,
            'filepath'  => '/',
            'filename'  => 'sandbox-test.mbz',
        ], $source);
    }
    // Reflect the uploaded file in the stored-file setting so it shows on the settings page.
    set_config('coursebackups', '/sandbox-test.mbz', 'local_sandbox');

    // Enable the (by default disabled) scheduled task so the setup looks production-ready.
    $DB->execute(
        'UPDATE {task_scheduled} SET disabled = 0 WHERE ' . $DB->sql_like('classname', ':cn'),
        ['cn' => '%local_sandbox%restore_courses%']
    );

    // Run the sandbox restore once so the demo course is actually reset from the
    // backup, proving the plugin works end to end. Keep provisioning resilient:
    // even if the restore hiccups, the plugin stays installed and configured.
    try {
        ob_start();
        try {
            $task = new \local_sandbox\task\restore_courses();
            $task->execute();
        } finally {
            $restorestatus = ob_get_clean();
        }
    } catch (\Throwable $re) {
        $restorestatus = 'EXCEPTION: ' . $re->getMessage();
    }

    // The task recreates/clears the course; confirm it still exists.
    if (!$DB->record_exists('course', ['shortname' => 'sandbox-test'])) {
        throw new \RuntimeException("The 'sandbox-test' sandbox course is missing after the restore run.");
    }

    echo "Provisioned local_sandbox demo: 'sandbox-test' course + sandbox-test.mbz backup, task enabled and executed.\n";
    echo $restorestatus . "\n";
} catch (\Throwable $e) {
    fwrite(STDERR, 'local_sandbox demo provisioning failed: ' . $e->getMessage() . "\n");
}
